// ops.sql.go — hand-written sqlc query implementations for ops schema.
// These would normally be generated by sqlc from ops.sql.
// Written by hand because sqlc binary is not available in the sandbox.

package sqlc

import (
	"context"
)

// ---------------------------------------------------------------------------
// Room allocation queries
// ---------------------------------------------------------------------------

const upsertRoomAllocation = `-- name: UpsertRoomAllocation :one
INSERT INTO ops.room_allocations (departure_id, status)
VALUES ($1, 'draft')
ON CONFLICT (departure_id) DO UPDATE
  SET updated_at = now()
WHERE ops.room_allocations.status = 'draft'
RETURNING id, departure_id, status, committed_at, created_at, updated_at
`

// UpsertRoomAllocation inserts a new draft allocation or returns the existing
// draft for the departure. Returns error if status is not 'draft'.
func (q *Queries) UpsertRoomAllocation(ctx context.Context, departureID string) (RoomAllocation, error) {
	row := q.db.QueryRow(ctx, upsertRoomAllocation, departureID)
	var i RoomAllocation
	err := row.Scan(
		&i.ID,
		&i.DepartureID,
		&i.Status,
		&i.CommittedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

const getRoomAllocationByDepartureID = `-- name: GetRoomAllocationByDepartureID :one
SELECT id, departure_id, status, committed_at, created_at, updated_at
FROM ops.room_allocations
WHERE departure_id = $1
`

func (q *Queries) GetRoomAllocationByDepartureID(ctx context.Context, departureID string) (RoomAllocation, error) {
	row := q.db.QueryRow(ctx, getRoomAllocationByDepartureID, departureID)
	var i RoomAllocation
	err := row.Scan(
		&i.ID,
		&i.DepartureID,
		&i.Status,
		&i.CommittedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

